    "sql_query": "SELECT Fname, LName FROM Student WHERE StuID NOT IN (SELECT StuID FROM Has_Allergy WHERE Allergy IN (SELECT Allergy FROM Allergy_Type WHERE AllergyType LIKE \'Food%\'))",
    "summary": "Selects student first and last name who do not have any food type allergy"
