{
    "sql_query": "SELECT COUNT(*) AS male_food_allergy_count FROM Student WHERE Sex = 'M' AND StuID IN (SELECT StuID FROM Has_Allergy WHERE Allergy IN (SELECT Allergy FROM Allergy_Type WHERE AllergyType LIKE \'%food%\'))",
    "summary": "Counts the number of male students who have a food allergy."
